<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Memory Game - Break</title>
    <link rel="stylesheet" href="CSS/style.css">
    <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.0/css/all.min.css">
</head>
<body>
  <section class="game"> 
    <div id="menu">
      <h2 style="grid-column: span 2; margin-bottom: 10px;">Choose Game Type</h2>
      <button onclick="startGame('fruits')">Fruits 🍎</button>
      <button onclick="startGame('animals')">Animals 🐶</button>
      <button onclick="startGame('emojis')">Emojis 😀</button>
      <button onclick="startGame('food')">Food 🍕</button>
      <button onclick="startGame('sports')">Sports ⚽</button>
      <button onclick="startGame('symbols')">Symbols ⭐</button>
    </div>
    <div id="timer"></div>
    <div class="game-board" id="board"></div>
    <div id="overlay" class="overlay"></div>
  </section>
  <section class="alert_finished_game" style="display: none;">
    <nav>
  <svg width="55" height="55" viewBox="0 2 90 95" fill="none" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
	<path d="M0 30C0 13.4315 13.4315 0 30 0H58C74.5685 0 88 13.4315 88 30V88H0V30Z" fill="url(#pattern0_122_472)"/>
	<defs>
	<pattern id="pattern0_122_472" patternContentUnits="objectBoundingBox" width="1" height="1">
	<use xlink:href="#image0_122_472" transform="scale(0.00195312)"/>
	</pattern>
	</defs>
	<image id="image0_122_472" width="512" height="512" preserveAspectRatio="none" xlink:href="data:image/png;base64,"/>
	</svg>
    <p>Time's Up!</p>
    </nav>
    <h1>You've been on break for too long!</h1>
    <p class="sub">It's time to get back to studying</p>
    <button id="back-to-room-btn">Return to Study</button>
  </section>
  <div id="global-break-timer" class="custom-break-counter">
    <span class="timer-icon">⏳</span>
    <span class="timer-text">Break Remaining: </span>
    <span id="break-clock-digits">00:00</span>
  </div>
  <script src="JS/script.js"></script>
</body>
</html>